import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';
dayjs.extend(customParseFormat);
export const processCombinedData = (csvData, excelRaw, proyectadoManual = 239000) => {
  if (!csvData || !excelRaw) return null;

  // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
  const workbook = XLSX.read(excelRaw, {
    type: 'array'
  });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];

  // Obtenemos los datos como una matriz de arrays para mayor control
  const rows = XLSX.utils.sheet_to_json(sheet, {
    header: 1,
    defval: ""
  });

  // La fila 4 (índice 3) contiene los encabezados
  const rawHeaders = rows[3] || [];
  const cleanHeaders = rawHeaders.map(h => String(h).trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""));

  // Buscamos los índices de las columnas dinámicamente
  const idxCant = cleanHeaders.findIndex(h => h.includes("CANT") && h.includes("PAQUETE"));
  const idxTipoOp = cleanHeaders.findIndex(h => h.includes("TIPO") && h.includes("OPERACION"));
  const idxAccion = cleanHeaders.findIndex(h => h.includes("ACCION"));
  const idxFecha = cleanHeaders.findIndex(h => h.includes("FECHA") && h.includes("HORA"));
  const idxTransporte = cleanHeaders.findIndex(h => h.includes("TRANSPORTE"));

  // Procesamos los datos desde la fila 5
  const easyDockingClean = rows.slice(4).filter(row => {
    const tipoOp = String(row[idxTipoOp] || "").toUpperCase();
    const accion = String(row[idxAccion] || "").toLowerCase();
    return tipoOp.includes("DESCARGA") && accion === "add";
  });
  const totalArribadosFisicos = easyDockingClean.reduce((acc, row) => acc + (parseFloat(row[idxCant]) || 0), 0);

  // --- 2. PROCESAR CSV (TMS) ---
  // Buscamos la columna de bipeo de forma flexible
  const firstRow = csvData[0] || {};
  const colBipeo = Object.keys(firstRow).find(k => k.toLowerCase().includes("labeling") && k.toLowerCase().includes("printed"));
  const totalPiezasSistema = csvData.length;
  const totalBipeadasReal = csvData.filter(d => d[colBipeo] && String(d[colBipeo]).trim() !== "").length;

  // --- 3. CÁLCULO DE TIEMPO (CIERRE 22:00) ---
  const ahora = dayjs();
  const horaCierre = dayjs().set('hour', 22).set('minute', 0).set('second', 0);
  let horasRestantes = horaCierre.diff(ahora, 'hour', true);
  if (horasRestantes <= 0) horasRestantes = 0.5;
  const objXHora = Math.round((proyectadoManual - totalPiezasSistema) / horasRestantes);

  // --- 4. CONFIGURAR GRÁFICA (05:00 A 23:00) ---
  const franjas = Array.from({
    length: 19
  }, (_, i) => `${(i + 5).toString().padStart(2, '0')}:00`);
  const chartMap = {};
  franjas.forEach(h => chartMap[h] = {
    hora: h,
    arribo: 0,
    bipeo: 0
  });
  easyDockingClean.forEach(row => {
    const rawDate = row[idxFecha];
    if (rawDate) {
      const hora = dayjs(rawDate).format('HH:00');
      if (chartMap[hora]) chartMap[hora].arribo += parseFloat(row[idxCant]) || 0;
    }
  });
  csvData.forEach(row => {
    const rawDate = row[colBipeo];
    if (rawDate) {
      const hora = dayjs(rawDate, "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });
  return {
    kpis: {
      proyectado: proyectadoManual.toLocaleString(),
      arribados: totalArribadosFisicos.toLocaleString(),
      total: totalPiezasSistema.toLocaleString(),
      descargaHora: objXHora > 0 ? objXHora.toLocaleString() : "FINALIZADO",
      arribadoBipeado: (totalArribadosFisicos - totalPiezasSistema).toLocaleString(),
      proyectadoBipeado: (proyectadoManual - totalPiezasSistema).toLocaleString(),
      pArribado: Math.round(totalArribadosFisicos / proyectadoManual * 100) || 0,
      pBipeo: Math.round(totalPiezasSistema / proyectadoManual * 100) || 0,
      velocidadReal: 90
    },
    chartData: Object.values(chartMap),
    tableData: franjas.map(h => ({
      intervalo: h,
      etiquetado: Math.round(proyectadoManual / 19),
      piezas: chartMap[h].bipeo,
      usuarios: 12
    })),
    matrix: {
      chasis: easyDockingClean.filter(row => String(row[idxTransporte] || "").includes("Chasis")).length,
      camioneta: easyDockingClean.filter(row => String(row[idxTransporte] || "").toLowerCase().includes("camioneta")).length,
      semi: easyDockingClean.filter(row => String(row[idxTransporte] || "").includes("Semi")).length
    }
  };
};

